on start
{
  dword adapterCount;
  dword ifIndex;
  word prio;
  long result;
  adapterCount = ipGetAdapterCount();

  for(ifIndex = 1; ifIndex <= adapterCount; ifIndex++)
  {
    result = IpGetAdapterVlanDefaultPriority (ifIndex, prio);
    if(result == 0)
    {
      write("Adapter %d has VLAN priority %d", ifIndex, prio);
    }
  }
}
